import requests
import json

url = "https://partner.shopeemobile.com/api/v2/product/add_model?access_token=access_token&partner_id=partner_id&shop_id=shop_id&sign=sign&timestamp=timestamp"

payload=json.dumps({
  "model_list": [
    {
      "gtin_code": "-",
      "model_sku": "SKU",
      "original_price": 38.3,
      "seller_stock": [
        {
          "location_id": "-",
          "stock": 0
        }
      ],
      "weight": 1.1
    }
  ]
})
headers = {
  'Content-Type': 'application/json'
}
response = requests.RPCRequest("POST",url,headers=headers, data=payload, allow_redirects=False)

print(response.text)
